/**
 * Pure validation functions for order operations.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';

const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

export function validateOrderStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!STATUS_TRANSITIONS[from].includes(to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

export function validateOrderUserExists(
  user: User | undefined,
  userId: string,
): void {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

export function validateOrderExists(
  order: { id: string } | undefined,
  orderId: string,
): void {
  if (!order) {
    throw new Error(`Order not found: ${orderId}`);
  }
}

/**
 * Pure validation functions for user operations.
 */

import type { User } from '../models/user.js';

export function validateEmailNotTaken(
  existingUser: User | undefined,
  email: string,
): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

export function validateEmailNotInUse(
  existingUser: User | undefined,
  email: string,
): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

export function validateUserExists(
  user: User | undefined,
  userId: string,
): void {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Pure validation functions for preferences operations.
 */

import type { User } from '../models/user.js';
import type { UserPreferences } from '../models/user-preferences.js';

export function validatePreferencesUserExists(
  user: User | undefined,
  userId: string,
): void {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

export function validatePreferencesNotExist(
  existing: UserPreferences | undefined,
  userId: string,
): void {
  if (existing) {
    throw new Error(`Preferences already exist for user: ${userId}`);
  }
}

export function validatePreferencesExist(
  existing: UserPreferences | undefined,
  userId: string,
): void {
  if (!existing) {
    throw new Error(`Preferences not found for user: ${userId}`);
  }
}

