import { describe, it, expect } from 'vitest';
import {
  validateOrderItems,
  validateOrderStatusTransition,
  validateOrderUserExists,
  validateOrderExists,
} from '../../src/validators/order.validator.js';
import type { User } from '../../src/models/user.js';
import type { OrderStatus } from '../../src/models/order.js';

describe('order validators', () => {
  describe('validateOrderItems', () => {
    it('should throw for empty items', () => {
      expect(() => validateOrderItems([])).toThrow('at least one item');
    });

    it('should not throw for non-empty items', () => {
      expect(() =>
        validateOrderItems([{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }]),
      ).not.toThrow();
    });
  });

  describe('validateOrderStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(() => validateOrderStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should allow pending -> cancelled', () => {
      expect(() => validateOrderStatusTransition('pending', 'cancelled')).not.toThrow();
    });

    it('should allow confirmed -> shipped', () => {
      expect(() => validateOrderStatusTransition('confirmed', 'shipped')).not.toThrow();
    });

    it('should allow confirmed -> cancelled', () => {
      expect(() => validateOrderStatusTransition('confirmed', 'cancelled')).not.toThrow();
    });

    it('should allow shipped -> delivered', () => {
      expect(() => validateOrderStatusTransition('shipped', 'delivered')).not.toThrow();
    });

    it('should reject pending -> delivered', () => {
      expect(() => validateOrderStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should reject delivered -> any', () => {
      const targets: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'cancelled'];
      for (const to of targets) {
        expect(() => validateOrderStatusTransition('delivered', to)).toThrow(
          'Invalid status transition',
        );
      }
    });

    it('should reject cancelled -> any', () => {
      const targets: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered'];
      for (const to of targets) {
        expect(() => validateOrderStatusTransition('cancelled', to)).toThrow(
          'Invalid status transition',
        );
      }
    });
  });

  describe('validateOrderUserExists', () => {
    it('should throw if user is undefined', () => {
      expect(() => validateOrderUserExists(undefined, 'user-1')).toThrow('User not found: user-1');
    });

    it('should not throw if user exists', () => {
      const user: User = {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      };
      expect(() => validateOrderUserExists(user, 'user-1')).not.toThrow();
    });
  });

  describe('validateOrderExists', () => {
    it('should throw if order is undefined', () => {
      expect(() => validateOrderExists(undefined, 'order-1')).toThrow('Order not found: order-1');
    });

    it('should not throw if order exists', () => {
      expect(() => validateOrderExists({ id: 'order-1' }, 'order-1')).not.toThrow();
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmailNotTaken,
  validateEmailNotInUse,
  validateUserExists,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides?: Partial<User>): User => ({
  id: 'user-1',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('user validators', () => {
  describe('validateEmailNotTaken', () => {
    it('should throw if a user with that email exists', () => {
      expect(() => validateEmailNotTaken(makeUser(), 'alice@example.com')).toThrow(
        'User with email alice@example.com already exists',
      );
    });

    it('should not throw if no user has that email', () => {
      expect(() => validateEmailNotTaken(undefined, 'alice@example.com')).not.toThrow();
    });
  });

  describe('validateEmailNotInUse', () => {
    it('should throw if a user with that email exists', () => {
      expect(() => validateEmailNotInUse(makeUser(), 'alice@example.com')).toThrow(
        'Email alice@example.com is already in use',
      );
    });

    it('should not throw if no user has that email', () => {
      expect(() => validateEmailNotInUse(undefined, 'alice@example.com')).not.toThrow();
    });
  });

  describe('validateUserExists', () => {
    it('should throw if user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-1')).toThrow('User not found: user-1');
    });

    it('should not throw if user exists', () => {
      expect(() => validateUserExists(makeUser(), 'user-1')).not.toThrow();
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validatePreferencesUserExists,
  validatePreferencesNotExist,
  validatePreferencesExist,
} from '../../src/validators/preferences.validator.js';
import type { User } from '../../src/models/user.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

const makeUser = (): User => ({
  id: 'user-1',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
});

const makePrefs = (): UserPreferences => ({
  id: 'pref-1',
  userId: 'user-1',
  email: {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: ['order-confirmation'],
  },
  createdAt: new Date(),
  updatedAt: new Date(),
});

describe('preferences validators', () => {
  describe('validatePreferencesUserExists', () => {
    it('should throw if user is undefined', () => {
      expect(() => validatePreferencesUserExists(undefined, 'user-1')).toThrow(
        'User not found: user-1',
      );
    });

    it('should not throw if user exists', () => {
      expect(() => validatePreferencesUserExists(makeUser(), 'user-1')).not.toThrow();
    });
  });

  describe('validatePreferencesNotExist', () => {
    it('should throw if preferences already exist', () => {
      expect(() => validatePreferencesNotExist(makePrefs(), 'user-1')).toThrow(
        'Preferences already exist for user: user-1',
      );
    });

    it('should not throw if no preferences exist', () => {
      expect(() => validatePreferencesNotExist(undefined, 'user-1')).not.toThrow();
    });
  });

  describe('validatePreferencesExist', () => {
    it('should throw if preferences do not exist', () => {
      expect(() => validatePreferencesExist(undefined, 'user-1')).toThrow(
        'Preferences not found for user: user-1',
      );
    });

    it('should not throw if preferences exist', () => {
      expect(() => validatePreferencesExist(makePrefs(), 'user-1')).not.toThrow();
    });
  });
});

